function Stopwatch() {
  // BUG: all the timer logic lives in the component.
  // Extract it into a custom hook (a function whose name starts with use) and call it here.
  const [seconds, setSeconds] = React.useState(0);

  React.useEffect(() => {
    const id = setInterval(() => setSeconds((s) => s + 1), 1000);
    return () => clearInterval(id);
  }, []);

  return (
    <div style={{ padding: '40px', fontFamily: 'sans-serif', color: '#e0e0e0', background: '#16213e', borderRadius: '8px', maxWidth: '420px', margin: '40px auto', textAlign: 'center' }}>
      <h2 style={{ marginTop: 0 }}>Stopwatch</h2>
      <span data-testid="seconds" style={{ fontSize: '3rem', color: '#e94560', fontWeight: 'bold' }}>{seconds}</span>
    </div>
  );
}
